module top_module(
    clk_i,
    rst_i,
    start_i,
    pc_i,
    pc_o
);input               clk_i;
input               rst_i;
input               start_i;
input   [31:0]      pc_i;
output  [31:0]      pc_o;


reg     [31:0]      pc_o;


  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk_i or negedge rst_i or posedge dbg_halt) begin
    if(~rst_i) begin
        pc_o <= 32'b0;
    end
    else begin
        if(start_i)
            pc_o <= pc_i;
        else
            pc_o <= pc_o;
    end
end

endmodule
